import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, retry, timeout } from 'rxjs';
import { Comment, CreateCommentInput } from '../models/comment.model';

interface ApiResponse<T> {
  data: T;
  message?: string;
  status: number;
}

@Injectable({ providedIn: 'root' })
export class CommentService {
  private http = inject(HttpClient);
  private readonly apiUrl = '/api/comments';
  private readonly REQUEST_TIMEOUT = 10000; // 10秒超时
  private readonly MAX_RETRIES = 2;

  getCommentsByPost(postId: string): Observable<Comment[]> {
    return this.http.get<Comment[]>(`${this.apiUrl}?postId=${postId}`)
      .pipe(
        timeout(this.REQUEST_TIMEOUT),
        retry(this.MAX_RETRIES)
      );
  }

  createComment(input: CreateCommentInput): Observable<Comment> {
    return this.http.post<Comment>(this.apiUrl, input)
      .pipe(
        timeout(this.REQUEST_TIMEOUT)
      );
  }

  likeComment(commentId: string): Observable<ApiResponse<Comment>> {
    return this.http.post<ApiResponse<Comment>>(`${this.apiUrl}/${commentId}/like`, {})
      .pipe(
        timeout(this.REQUEST_TIMEOUT),
        retry(1)
      );
  }

  deleteComment(commentId: string): Observable<void> {
    return this.http.delete<void>(`${this.apiUrl}/${commentId}`)
      .pipe(
        timeout(this.REQUEST_TIMEOUT),
        retry(this.MAX_RETRIES)
      );
  }
}

export interface Comment {
  id: string;
  postId?: string;
  content: string;
  author?: string;
  createdAt: Date;
  updatedAt?: Date;
  likes: number;
  likedByUser?: boolean;
  parentId?: string | null;
  userId?: string;
}

// 类型安全的创建类型
export type CreateCommentInput = Omit<Comment, 'id' | 'createdAt' | 'likes'>;

// 类型守卫函数
export function isValidComment(comment: unknown): comment is Comment {
  const c = comment as Comment;
  return !!(c?.id && c?.content && c?.author && c?.createdAt);
}

