import { Injectable, signal, computed, inject } from '@angular/core';
import { toObservable, toSignal } from '@angular/core/rxjs-interop';
import { Comment, CreateCommentInput } from '../models/comment.model';
import { CommentService } from '../services/comment.service';
import { catchError, finalize } from 'rxjs/operators';
import { of } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class CommentStore {
  private commentService = inject(CommentService);

  // 私有状态 signals
  private commentsSignal = signal<Comment[]>([]);
  private loadingSignal = signal<boolean>(false);
  private errorSignal = signal<string | null>(null);

  // 公共只读 computed 值
  readonly comments = this.commentsSignal.asReadonly();
  readonly isLoading = this.loadingSignal.asReadonly();
  readonly error = this.errorSignal.asReadonly();

  // 派生状态：计算评论总数
  readonly totalComments = computed(() => this.commentsSignal().length);

  // 派生状态：按时间倒序排列
  readonly sortedComments = computed(() => 
    [...this.commentsSignal()].sort((a, b) => 
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    )
  );

  // Actions
  loadComments(postId: string): void {
    this.loadingSignal.set(true);
    this.errorSignal.set(null);

    this.commentService.getCommentsByPost(postId)
      .pipe(
        catchError((err) => {
          this.errorSignal.set(err.message || '加载评论失败');
          return of([]);
        }),
        finalize(() => this.loadingSignal.set(false))
      )
      .subscribe((comments) => {
        this.commentsSignal.set(comments);
      });
  }

  addComment(input: CreateCommentInput): void {
    const newComment = {
      ...input,
      id: crypto.randomUUID(),
      createdAt: new Date(),
      likes: 0
    };

    // 乐观更新
    this.commentsSignal.update(prev => [newComment, ...prev]);

    this.commentService.createComment(input).subscribe({
      next: (serverComment) => {
        // 用服务器的真实数据替换临时数据
        this.commentsSignal.update(prev => 
          prev.map(c => c.id === newComment.id ? serverComment : c)
        );
      },
      error: (err) => {
        // 回滚
        this.commentsSignal.update(prev => 
          prev.filter(c => c.id !== newComment.id)
        );
        this.errorSignal.set(err.message || '添加评论失败');
      }
    });
  }

  likeComment(commentId: string): void {
    this.commentsSignal.update(prev =>
      prev.map(comment =>
        comment.id === commentId
          ? { ...comment, likes: comment.likes + 1 }
          : comment
      )
    );

    this.commentService.likeComment(commentId).subscribe({
      error: () => {
        // 回滚
        this.commentsSignal.update(prev =>
          prev.map(comment =>
            comment.id === commentId
              ? { ...comment, likes: comment.likes - 1 }
              : comment
          )
        );
      }
    });
  }
}

