      max-width: 600px;
    }

    .card__header {
      padding: 1rem;
      border-bottom: 1px solid #e5e7eb;
    }

    .card__title {
      margin: 0 0 0.25rem 0;
      font-size: 1.25rem;
      font-weight: 600;
      color: #111827;
    }

    .card__subtitle {
      font-size: 0.875rem;
      color: #6b7280;
    }

    .card__content {
      padding: 1rem;
    }

    .card__footer {
      padding: 1rem;
      border-top: 1px solid #e5e7eb;
      background: #f9fafb;
    }
  `]
})
export class CardComponent {
  @Input() title?: string;
  @Input() subtitle?: string;
  @Input() variant: CardVariant = 'default';
  @Input() size: CardSize = 'medium';
  @Input() width?: string;
  @Input() clickable = false;
  @Input() header = true;
  @Input() footer = false;

  @Output() cardClick = new EventEmitter<void>();

  onClick(): void {
    if (this.clickable) {
      this.cardClick.emit();
    }
  }
}

