import { Component, input, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { CommentStore } from './store/comment.store';
import { CommentListComponent } from './components/comment-list/comment-list.component';
import { AddCommentComponent } from './components/add-comment/add-comment.component';

@Component({
  selector: 'app-comments-feature',
  standalone: true,
  imports: [CommonModule, CommentListComponent, AddCommentComponent],
  template: `
    <div class="comments-container">
      <h2>评论 ({{ store.totalComments() }})</h2>

      <!-- 添加评论表单 -->
      <app-add-comment 
        [postId]="postId()" 
        (commentAdded)="onCommentAdded($event)"
      />

      <!-- 错误提示 -->
      @if (store.error()) {
        <div class="error-message" role="alert">
          {{ store.error() }}
          <button (click)="retryLoad()">重试</button>
        </div>
      }

      <!-- 加载状态 -->
      @if (store.isLoading()) {
        <div class="loading-state" aria-label="加载中">
          <div class="spinner"></div>
        </div>
      }

      <!-- 评论列表 -->
      @if (!store.isLoading()) {
        <app-comment-list 
          [comments]="store.sortedComments()"
          (likeClicked)="onLikeComment($event)"
        />
      }
    </div>
  `,
  styles: [`
    .comments-container {
      max-width: 800px;
      margin: 0 auto;
      padding: 20px;
    }

    .error-message {
      background: #fee;
      border: 1px solid #fcc;
      color: #c33;
      padding: 12px;
      border-radius: 8px;
      margin: 16px 0;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }

    .loading-state {
      display: flex;
      justify-content: center;
      padding: 40px;
    }

    .spinner {
      width: 40px;
      height: 40px;
      border: 3px solid #e0e0e0;
      border-top-color: #007bff;
      border-radius: 50%;
      animation: spin 0.8s linear infinite;
    }

    @keyframes spin {
      to { transform: rotate(360deg); }
    }
  `]
})
export class CommentsFeatureComponent implements OnInit {
  postId = input.required<string>();

  store = inject(CommentStore);

  ngOnInit(): void {
    this.retryLoad();
  }

  onCommentAdded(content: string): void {
    this.store.addComment({
      content,
      author: '当前用户', // 实际应从 AuthService 获取
      parentId: null
    });
  }

  onLikeComment(commentId: string): void {
    this.store.likeComment(commentId);
  }

  retryLoad(): void {
    this.store.loadComments(this.postId());
  }
}

